import{_ as n,c as s,o as a,V as e}from"./chunks/framework.1sOznGPE.js";const m=JSON.parse('{"title":"Vue自定义指令的原理是什么","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/指令/vue自定义指令的原理是什么.md","filePath":"guide/interview/vue/指令/vue自定义指令的原理是什么.md","lastUpdated":1719242077000}'),p={name:"guide/interview/vue/指令/vue自定义指令的原理是什么.md"},i=e(`<h1 id="vue自定义指令的原理是什么" tabindex="-1">Vue自定义指令的原理是什么 <a class="header-anchor" href="#vue自定义指令的原理是什么" aria-label="Permalink to &quot;Vue自定义指令的原理是什么&quot;">​</a></h1><p>指令本质上是装饰器，是 vue 对 HTML 元素的扩展，给 HTML 元素增加自定义功能。vue 编译 DOM 时，会找到指令对象，执行指令的相关方法。</p><p>自定义指令有五个生命周期（也叫钩子函数），分别是 bind、inserted、update、componentUpdated、unbind</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>1. bind：只调用一次，指令第一次绑定到元素时调用。在这里可以进行一次性的初始化设置。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. inserted：被绑定元素插入父节点时调用 (仅保证父节点存在，但不一定已被插入文档中)。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. update：被绑定于元素所在的模板更新时调用，而无论绑定值是否变化。通过比较更新前后的绑定值，可以忽略不必要的模板更新。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. componentUpdated：被绑定元素所在模板完成一次更新周期时调用。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. unbind：只调用一次，指令与元素解绑时调用。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>原理</strong></p><p>1.在生成 ast 语法树时，遇到指令会给当前元素添加 directives 属性</p><p>2.通过 genDirectives 生成指令代码</p><p>3.在 patch 前将指令的钩子提取到 cbs 中,在 patch 过程中调用对应的钩子</p><p>4.当执行指令对应钩子函数时，调用对应指令定义的方法</p>`,9),t=[i];function l(r,c,d,u,o,_){return a(),s("div",null,t)}const v=n(p,[["render",l]]);export{m as __pageData,v as default};
